import React, { useEffect, useState } from 'react';

const BookList = () => {
    const [books, setBooks] = useState([]);

    useEffect(()=>{
        fetch("http://localhost:3000/api/book")
        .then((response)=>response.json())
        .then((data)=> setBooks(data))
        .catch((error) => console.error("erro for the data fetching ",error))
    },[])
    return (
      <div>
        <h1 className='text-red-500 text-lg'>Liste des livres</h1>
        <ul className='flex items-center justify'>
          {books.map((book) => (
            <li key={book._id}>
              <h2>{book.title}</h2>
              <p>{book.description}</p>
              <p>Pages : {book.page}</p>
            </li>
          ))}
        </ul>
      </div>
    );
};

export default BookList;
